import{_ as s,o as a,c as i,a0 as t}from"./chunks/framework.CWk8AOcY.js";const k=JSON.parse('{"title":"连接到已有 Cube 集群","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/connect-existing-cluster.md","filePath":"zh/guide/connect-existing-cluster.md"}'),l={name:"zh/guide/connect-existing-cluster.md"};function n(d,e,h,p,o,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="连接到已有-cube-集群" tabindex="-1">连接到已有 Cube 集群 <a class="header-anchor" href="#连接到已有-cube-集群" aria-label="Permalink to &quot;连接到已有 Cube 集群&quot;">​</a></h1><p>如果你只是想尽快跑通，先看示例目录：</p><ul><li>示例代码：<a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar" target="_blank" rel="noreferrer">examples/e2b-dev-sidecar</a></li><li>中文说明：<a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar/README_zh.md" target="_blank" rel="noreferrer">README_zh.md</a></li><li>英文说明：<a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar/README.md" target="_blank" rel="noreferrer">README.md</a></li></ul><h2 id="为什么需要dev-sidecar" tabindex="-1">为什么需要dev-sidecar? <a class="header-anchor" href="#为什么需要dev-sidecar" aria-label="Permalink to &quot;为什么需要dev-sidecar?&quot;">​</a></h2><p>由于E2B需要沙箱URL是通过泛解析去解析到目标集群的public-ip，因此如果您是在生产环境中部署，您需要在私有dns中，添加一条A记录： <code>*.cube.app =&gt; &lt;your cube master node ip&gt;</code>.</p><p>而我们在开发阶段，在自己电脑上加泛解析是很麻烦的。因此我们做了个dev-sidecar,帮助您在不更改 E2B SDK的情况下，轻松的在开发机上连接Cube集群来创建实例。</p><p>这篇文档只做一件事：帮你更快判断自己该怎么填 <code>dev-sidecar</code> 的环境变量。</p><h2 id="先走成功路径" tabindex="-1">先走成功路径 <a class="header-anchor" href="#先走成功路径" aria-label="Permalink to &quot;先走成功路径&quot;">​</a></h2><h3 id="场景一-你是在本机先用-dev-env-起的-cube" tabindex="-1">场景一：你是在本机先用 <code>dev-env</code> 起的 Cube <a class="header-anchor" href="#场景一-你是在本机先用-dev-env-起的-cube" aria-label="Permalink to &quot;场景一：你是在本机先用 \`dev-env\` 起的 Cube&quot;">​</a></h3><p>这是 <code>dev-sidecar</code> 最自然、也最推荐的开发路径。</p><p>如果你是按 <a href="./dev-environment.html">开发环境（QEMU 虚机）</a> 启动的本地开发环境，那么 <code>examples/e2b-dev-sidecar/env.example</code> 里的默认值本来就是为这个场景准备的。</p><p>直接这样做：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/e2b-dev-sidecar</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>然后只需要补上模板 ID：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:13000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_REMOTE_PROXY_BASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://127.0.0.1:11443&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dummy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_TEMPLATE_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;your-template-id&gt;&quot;</span></span></code></pre></div><p>运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.py</span></span></code></pre></div><p>这里最关键的一点是：</p><ul><li><code>127.0.0.1:13000</code> 不是随便写的，它对应 <code>dev-env</code> 暴露出来的 CubeAPI</li><li><code>127.0.0.1:11443</code> 不是随便写的，它对应 <code>dev-env</code> 暴露出来的 CubeProxy</li></ul><p>也就是说，如果你本机已经起了 <code>dev-env</code>，通常不需要改地址，只需要填模板 ID。</p><h3 id="场景二-你要连接另一台机器上的已有-cube-集群" tabindex="-1">场景二：你要连接另一台机器上的已有 Cube 集群 <a class="header-anchor" href="#场景二-你要连接另一台机器上的已有-cube-集群" aria-label="Permalink to &quot;场景二：你要连接另一台机器上的已有 Cube 集群&quot;">​</a></h3><p>这时也还是用同一个 <code>dev-sidecar</code> 示例，只是把默认地址替换成远端集群的地址：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://&lt;node-ip&gt;:3000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_REMOTE_PROXY_BASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://&lt;node-ip&gt;:443&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dummy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_TEMPLATE_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;your-template-id&gt;&quot;</span></span></code></pre></div><p>然后同样运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.py</span></span></code></pre></div><h2 id="只记这几件事" tabindex="-1">只记这几件事 <a class="header-anchor" href="#只记这几件事" aria-label="Permalink to &quot;只记这几件事&quot;">​</a></h2><ul><li><code>E2B_API_URL</code> 控制面地址。<code>dev-env</code> 默认就是 <code>http://127.0.0.1:13000</code>。</li><li><code>CUBE_REMOTE_PROXY_BASE</code> 数据面地址。<code>dev-env</code> 默认就是 <code>https://127.0.0.1:11443</code>。</li><li><code>E2B_API_KEY</code> SDK 要求非空；如果你的集群开启鉴权，就填真实值，否则写<code>dummy</code>。</li><li><code>CUBE_TEMPLATE_ID</code> 你要创建沙箱时使用的模板 ID。</li></ul><p>其他配置项先不用急着看。绝大多数开发接入，先把这四个值弄对就够了。</p><h2 id="最容易踩的坑" tabindex="-1">最容易踩的坑 <a class="header-anchor" href="#最容易踩的坑" aria-label="Permalink to &quot;最容易踩的坑&quot;">​</a></h2><ul><li>本机明明跑的是 <code>dev-env</code>，却把地址写成了虚机内地址，而不是宿主机暴露出来的 <code>13000/11443</code></li><li>把 <code>CUBE_REMOTE_PROXY_BASE</code> 错写成 sidecar 自己的监听地址</li><li>忘了填 <code>CUBE_TEMPLATE_ID</code></li><li>集群开启了鉴权，但 <code>E2B_API_KEY</code> 还在用 dummy</li></ul><h2 id="进一步阅读" tabindex="-1">进一步阅读 <a class="header-anchor" href="#进一步阅读" aria-label="Permalink to &quot;进一步阅读&quot;">​</a></h2><p>如果你想直接看最容易理解的版本，优先看示例 README：</p><ul><li><a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar/README_zh.md" target="_blank" rel="noreferrer">examples/e2b-dev-sidecar/README_zh.md</a></li></ul><p>如果你已经准备把 sidecar 接到自己的代码里，再回头看示例里的：</p><ul><li><code>demo.py</code></li><li><code>dev_sidecar.py</code></li></ul>`,35)])])}const u=s(l,[["render",n]]);export{k as __pageData,u as default};
